class Solution:
    def maxProfit(self, prices: List[int]) -> int:
        buy1, buy2 = -prices[0], -prices[0]
        profit1, profit2 = 0, 0

        for price in prices:
            buy1 = max(buy1, -price)
            profit1 = max(profit1, price + buy1)
            buy2 = max(buy2, profit1 - price)
            profit2 = max(profit2, price + buy2)

        return profit2
